// // This module implements a T-flip-flop that toggles its output (Q) on the falling edge of the clock when the T input is low.
module TFlipFlop (
    input wire T,
    input wire clk,
    input wire reset,
    output reg Q
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            Q <= 0;
        end else if (T) begin
            Q <= ~Q;
        end
    end
endmodule
